import { useState, useCallback, useEffect, useMemo } from 'react';
import { supabase } from '../services/supabaseClient';
import { Bank, Church, ChurchFormData, LearnedAssociation, MatchResult, FileModel } from '../types';
import { usePersistentState } from './usePersistentState';
import { Logger } from '../services/monitoringService';
import { normalizeString, DEFAULT_CONTRIBUTION_KEYWORDS } from '../services/processingService';
import { useAuth } from '../contexts/AuthContext';
import { modelService } from '../services/modelService';

const DEFAULT_IGNORE_KEYWORDS = [
    'DÍZIMOS', 'OFERTAS', 'MISSÕES', 'TERRENO - NOVA SEDE', 'PIX', 'TED', 'DOC',
    'Transferência', 'Pagamento', 'Recebimento', 'Depósito', 'Contribuição',
    'Sr', 'Sra', 'Dr', 'Dra', 'RECEB OUTRA IF'
];

export const useReferenceData = (user: any | null, showToast: (msg: string, type: 'success' | 'error') => void) => {
    const { subscription } = useAuth();
    const userSuffix = user ? `-${user.id}` : '-guest';

    // --- State ---
    const [banks, setBanks] = usePersistentState<Bank[]>(`identificapix-banks${userSuffix}`, []);
    const [churches, setChurches] = usePersistentState<Church[]>(`identificapix-churches${userSuffix}`, []);
    const [fileModels, setFileModels] = useState<FileModel[]>([]);
    const [similarityLevel, setSimilarityLevel] = usePersistentState<number>(`identificapix-similarity${userSuffix}`, 55);
    const [dayTolerance, setDayTolerance] = usePersistentState<number>(`identificapix-daytolerance${userSuffix}`, 2);

    // Keywords
    const [customIgnoreKeywords, setCustomIgnoreKeywords] = usePersistentState<string[]>(`identificapix-ignore-keywords${userSuffix}`, DEFAULT_IGNORE_KEYWORDS);
    const [contributionKeywords, setContributionKeywords] = usePersistentState<string[]>(`identificapix-contribution-types${userSuffix}`, DEFAULT_CONTRIBUTION_KEYWORDS);

    const [learnedAssociations, setLearnedAssociations] = useState<LearnedAssociation[]>([]);

    const [editingBank, setEditingBank] = useState<Bank | null>(null);
    const [editingChurch, setEditingChurch] = useState<Church | null>(null);

    // --- Methods for Keywords ---
    const addIgnoreKeyword = useCallback((k: string) => {
        if (!k.trim()) return;
        setCustomIgnoreKeywords(prev => prev.includes(k.trim()) ? prev : [...prev, k.trim()]);
    }, [setCustomIgnoreKeywords]);

    const removeIgnoreKeyword = useCallback((k: string) => setCustomIgnoreKeywords(prev => prev.filter(i => i !== k)), [setCustomIgnoreKeywords]);

    const addContributionKeyword = useCallback((k: string) => {
        if (!k.trim()) return;
        setContributionKeywords(prev => {
            const normalized = k.toUpperCase().trim();
            return prev.includes(normalized) ? prev : [...prev, normalized];
        });
    }, [setContributionKeywords]);

    const removeContributionKeyword = useCallback((k: string) => setContributionKeywords(prev => prev.filter(i => i !== k)), [setContributionKeywords]);

    // --- Sincronização de Dados (Recuperação do Banco) ---
    useEffect(() => {
        if (!user) return;

        const syncData = async () => {
            try {
                // Sincroniza Bancos
                const { data: banksData } = await supabase
                    .from('banks')
                    .select('*')
                    .eq('user_id', user.id);

                if (banksData) {
                    setBanks(prev => {
                        // Merge para evitar perder temporários, mas prioriza DB
                        const dbIds = new Set(banksData.map(b => b.id));
                        const localOnly = prev.filter(b => b.id.startsWith('temp-') || !dbIds.has(b.id));
                        // Se o DB retornou dados, usamos eles como fonte de verdade + locais temporários
                        return banksData.length > 0 ? [...banksData, ...localOnly.filter(l => l.id.startsWith('temp-'))] : prev;
                    });
                }

                // Sincroniza Igrejas
                const { data: churchesData } = await supabase
                    .from('churches')
                    .select('*')
                    .eq('user_id', user.id);

                if (churchesData) {
                    setChurches(prev => {
                        const dbIds = new Set(churchesData.map(c => c.id));
                        const localOnly = prev.filter(c => c.id.startsWith('temp-') || !dbIds.has(c.id));
                        return churchesData.length > 0 ? [...churchesData, ...localOnly.filter(l => l.id.startsWith('temp-'))] : prev;
                    });
                }
            } catch (e) {
                console.error("Erro ao sincronizar cadastros:", e);
            }
        };

        syncData();
    }, [user, setBanks, setChurches]);

    // --- Fetch Models ---
    const fetchModels = useCallback(async () => {
        if (!user) return;
        try {
            const models = await modelService.getUserModels(user.id);
            setFileModels(models);
        } catch (e) {
            console.error("Failed to fetch models", e);
        }
    }, [user]);

    useEffect(() => {
        fetchModels();
    }, [fetchModels]);

    const openEditBank = useCallback((bank: Bank) => setEditingBank(bank), []);
    const closeEditBank = useCallback(() => setEditingBank(null), []);

    const updateBank = useCallback(async (bankId: string, name: string) => {
        if(!user) return;
        const oldBanks = [...banks];
        setBanks(prev => prev.map(b => b.id === bankId ? { ...b, name } : b));
        closeEditBank();
        const { error } = await supabase.from('banks').update({ name }).eq('id', bankId);
        if (error) { setBanks(oldBanks); showToast('Erro ao atualizar banco.', 'error'); }
        else showToast('Banco atualizado com sucesso.', 'success');
    }, [user, banks, setBanks, closeEditBank, showToast]);

    const addBank = useCallback(async (name: string): Promise<boolean> => {
        if(!user) { showToast("Você precisa estar logado.", "error"); return false; }
        if (banks.length >= (subscription.maxBanks || 1)) {
            showToast(`Limite atingido (${subscription.maxBanks}).`, 'error');
            return false;
        }
        const tempId = `temp-${Date.now()}`;
        setBanks(prev => [...prev, { id: tempId, name }]);
        try {
            const { data, error } = await supabase.from('banks').insert([{ name, user_id: user.id }]).select();
            if (error || !data) { setBanks(prev => prev.filter(b => b.id !== tempId)); return false; }
            setBanks(prev => prev.map(b => b.id === tempId ? { ...b, id: data[0].id } : b));
            showToast('Banco adicionado.', 'success');
            return true;
        } catch (e) { return false; }
    }, [user, setBanks, showToast, banks.length, subscription.maxBanks]);

    const openEditChurch = useCallback((church: Church) => setEditingChurch(church), []);
    const closeEditChurch = useCallback(() => setEditingChurch(null), []);

    const updateChurch = useCallback(async (churchId: string, formData: ChurchFormData) => {
        if(!user) return;
        const oldChurches = [...churches];
        setChurches(prev => prev.map(c => c.id === churchId ? { ...c, ...formData } : c));
        closeEditChurch();
        const { error } = await supabase.from('churches').update(formData).eq('id', churchId);
        if (error) { setChurches(oldChurches); showToast('Erro ao atualizar igreja.', 'error'); }
        else showToast('Igreja atualizada.', 'success');
    }, [user, churches, setChurches, closeEditChurch, showToast]);

    const addChurch = useCallback(async (formData: ChurchFormData): Promise<boolean> => {
        if(!user) return false;
        if (churches.length >= (subscription.maxChurches || 1)) {
            showToast(`Limite atingido (${subscription.maxChurches}).`, 'error');
            return false;
        }
        const tempId = `temp-${Date.now()}`;
        setChurches(prev => [...prev, { id: tempId, ...formData }]);
        try {
            const { data, error } = await supabase.from('churches').insert([{ ...formData, user_id: user.id }]).select();
            if (error || !data) { setChurches(prev => prev.filter(c => c.id !== tempId)); return false; }
            setChurches(prev => prev.map(c => c.id === tempId ? { ...c, id: data[0].id } : c));
            showToast('Igreja adicionada.', 'success');
            return true;
        } catch (e) { return false; }
    }, [user, setChurches, showToast, churches.length, subscription.maxChurches]);

    useEffect(() => {
        if (!user) return;
        const fetchAssociations = async () => {
            const { data } = await supabase.from('learned_associations').select('*').eq('user_id', user.id);
            if (data) {
                const mapped: LearnedAssociation[] = data.map(d => ({
                    id: d.id, normalizedDescription: d.normalized_description,
                    contributorNormalizedName: d.contributor_normalized_name,
                    churchId: d.church_id, user_id: d.user_id
                }));
                setLearnedAssociations(mapped);
            }
        };
        fetchAssociations();
    }, [user]);

    const learnAssociation = useCallback(async (matchResult: MatchResult) => {
        if (!user || !matchResult.contributor || !matchResult.church) return;
        const normalizedDesc = normalizeString(matchResult.transaction.description, customIgnoreKeywords);
        const normalizedContrib = matchResult.contributor.normalizedName || normalizeString(matchResult.contributor.name, customIgnoreKeywords);
        if (learnedAssociations.some(la => la.normalizedDescription === normalizedDesc && la.contributorNormalizedName === normalizedContrib && la.churchId === matchResult.church.id)) return;
        const newAssociation: LearnedAssociation = { normalizedDescription: normalizedDesc, contributorNormalizedName: normalizedContrib, churchId: matchResult.church.id, user_id: user.id };
        setLearnedAssociations(prev => [...prev, newAssociation]);
        try {
            await supabase.from('learned_associations').insert({ user_id: user.id, normalized_description: normalizedDesc, contributor_normalized_name: normalizedContrib, church_id: matchResult.church.id });
        } catch (err) { setLearnedAssociations(prev => prev.filter(la => la.normalizedDescription !== normalizedDesc)); }
    }, [user, customIgnoreKeywords, learnedAssociations]);

    return useMemo(() => ({
        banks, setBanks,
        churches, setChurches,
        fileModels, fetchModels,
        similarityLevel, setSimilarityLevel,
        dayTolerance, setDayTolerance,
        customIgnoreKeywords, setCustomIgnoreKeywords, addIgnoreKeyword, removeIgnoreKeyword,
        contributionKeywords, setContributionKeywords, addContributionKeyword, removeContributionKeyword,
        learnedAssociations, setLearnedAssociations, learnAssociation,
        editingBank, openEditBank, closeEditBank, updateBank, addBank,
        editingChurch, openEditChurch, closeEditChurch, updateChurch, addChurch
    }), [banks, churches, fileModels, fetchModels, similarityLevel, dayTolerance, customIgnoreKeywords, contributionKeywords, learnedAssociations, editingBank, editingChurch, setBanks, setChurches, setSimilarityLevel, setDayTolerance, setCustomIgnoreKeywords, setContributionKeywords, addIgnoreKeyword, removeIgnoreKeyword, addContributionKeyword, removeContributionKeyword, setLearnedAssociations, learnAssociation, openEditBank, closeEditBank, updateBank, addBank, openEditChurch, closeEditChurch, updateChurch, addChurch]);
};

import { useState, useCallback, useMemo, useEffect } from 'react';
import { usePersistentState } from './usePersistentState';
import { 
    Transaction, 
    Contributor, 
    MatchResult, 
    Church, 
    Bank, 
    FileModel, 
    GroupedReportData, 
    ComparisonType,
    ViewType,
    LearnedAssociation
} from '../types';
import { 
    matchTransactions, 
    groupResultsByChurch, 
    PLACEHOLDER_CHURCH,
    normalizeString,
    processFileContent
} from '../services/processingService';
import { consolidationService } from '../services/ConsolidationService';
import { getAISuggestion } from '../services/geminiService';

interface UseReconciliationProps {
    user: any | null; // Changed to any
    churches: Church[];
    banks: Bank[];
    fileModels: FileModel[];
    similarityLevel: number;
    dayTolerance: number;
    customIgnoreKeywords: string[];
    contributionKeywords: string[];
    learnedAssociations: LearnedAssociation[];
    showToast: (msg: string, type?: 'success' | 'error') => void;
    setIsLoading: (loading: boolean) => void;
    setActiveView: (view: ViewType) => void;
}

export const useReconciliation = ({
    user,
    churches,
    banks,
    fileModels,
    similarityLevel,
    dayTolerance,
    customIgnoreKeywords,
    contributionKeywords,
    learnedAssociations,
    showToast,
    setIsLoading,
    setActiveView
}: UseReconciliationProps) => {

    const userSuffix = user ? `-${user.id}` : '-guest';

    const [activeBankFiles, setBankStatementFile] = usePersistentState<{ 
        bankId: string, 
        content: string, 
        fileName: string, 
        rawFile?: File,
        processedTransactions?: Transaction[]
    }[]>(`identificapix-bank-files-v1${userSuffix}`, [], true);

    const [selectedBankIds, setSelectedBankIds] = usePersistentState<string[]>(`identificapix-selected-banks-v1${userSuffix}`, [], false);

    const [contributorFiles, setContributorFiles] = usePersistentState<{ churchId: string; content: string; fileName: string, contributors?: Contributor[] }[]>(`identificapix-contributors-v6${userSuffix}`, [], true);
    const [matchResults, setMatchResults] = usePersistentState<MatchResult[]>(`identificapix-results-v6${userSuffix}`, [], true);
    const [reportPreviewData, setReportPreviewData] = usePersistentState<{ income: GroupedReportData; expenses: GroupedReportData } | null>(`identificapix-report-preview-v6${userSuffix}`, null, true);
    const [hasActiveSession, setHasActiveSession] = usePersistentState<boolean>(`identificapix-has-session-v6${userSuffix}`, false, false);
    const [activeReportId, setActiveReportId] = usePersistentState<string | null>(`identificapix-active-report-id${userSuffix}`, null, false);

    const [comparisonType, setComparisonType] = useState<ComparisonType>('both');
    const [pendingTraining, setPendingTraining] = useState<{ content: string; fileName: string; type: 'statement' | 'contributor'; entityId: string, rawFile?: File } | null>(null);

    const [manualIdentificationTx, setManualIdentificationTx] = useState<Transaction | null>(null);
    const [bulkIdentificationTxs, setBulkIdentificationTxs] = useState<Transaction[] | null>(null);
    const [manualMatchState, setManualMatchState] = useState<{ record: MatchResult, suggestions: Transaction[] } | null>(null);
    const [divergenceConfirmation, setDivergenceConfirmation] = useState<MatchResult | null>(null);
    const [loadingAiId, setLoadingAiId] = useState<string | null>(null);
    const [aiSuggestion, setAiSuggestion] = useState<{ id: string, name: string } | null>(null);

    const cleaningKeywords = useMemo(() => {
        return Array.from(new Set([...customIgnoreKeywords, ...contributionKeywords]));
    }, [customIgnoreKeywords, contributionKeywords]);

    const toggleBankSelection = useCallback((bankId: string) => {
        setSelectedBankIds(prev => {
            if (prev.includes(bankId)) return prev.filter(id => id !== bankId);
            return [...prev, bankId];
        });
    }, [setSelectedBankIds]);

    const handleStatementUpload = useCallback((content: string, fileName: string, bankId: string, rawFile: File) => {
        setIsLoading(true);
        try {
            const result = processFileContent(content, fileName, fileModels, cleaningKeywords);
            const transactions = result.transactions;

            if (transactions.length > 0) {
                setBankStatementFile(prevFiles => {
                    const existingIndex = prevFiles.findIndex(f => f.bankId === bankId);
                    const newEntry = { 
                        bankId, 
                        content, 
                        fileName, 
                        rawFile,
                        processedTransactions: transactions 
                    };

                    if (existingIndex >= 0) {
                        const updated = [...prevFiles];
                        updated[existingIndex] = newEntry;
                        return updated;
                    } else {
                        return [...prevFiles, newEntry];
                    }
                });

                setSelectedBankIds(prev => prev.includes(bankId) ? prev : [...prev, bankId]);

                if (result.appliedModel) {
                    showToast("Modelo identificado e aplicado.", "success");
                } else {
                    showToast(`Extrato carregado.`, 'success');
                }

                if (user) {
                    const consolidationData = transactions.map(t => ({
                        transaction_date: t.date,
                        amount: t.amount,
                        description: t.description,
                        type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                        pix_key: null,
                        source: 'file' as 'file',
                        user_id: user.id,
                        bank_id: bankId 
                    }));

                    consolidationService.addTransactions(consolidationData)
                        .catch(err => console.warn("[Consolidation] Background sync skipped:", err));
                }

            } else {
                showToast("Formato de arquivo não reconhecido.", "error");
            }
        } catch (e: any) {
            console.error(e);
            showToast("Erro ao ler o arquivo: " + e.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [setBankStatementFile, setSelectedBankIds, showToast, setIsLoading, fileModels, cleaningKeywords, user]);

    const handleContributorsUpload = useCallback((content: string, fileName: string, churchId: string, rawFile?: File) => {
        setIsLoading(true);
        try {
            const result = processFileContent(content, fileName, fileModels, cleaningKeywords);
            const transactions = result.transactions;

            const contributors: Contributor[] = transactions.map(t => ({
                name: t.description,
                cleanedName: t.cleanedDescription,
                normalizedName: normalizeString(t.description, cleaningKeywords),
                amount: t.amount,
                date: t.date,
                originalAmount: t.originalAmount,
                contributionType: t.contributionType
            }));

            if (contributors.length > 0) {
                setContributorFiles(prev => {
                    const other = prev.filter(f => f.churchId !== churchId);
                    return [...other, { churchId, content, fileName, contributors }];
                });
                showToast(`Lista carregada.`, 'success');
            } else {
                showToast("Formato de lista não reconhecido.", "error");
            }
        } catch (e: any) {
            showToast("Erro ao ler o arquivo: " + e.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [cleaningKeywords, setContributorFiles, showToast, setIsLoading, fileModels]);

    const handleTrainingSuccess = useCallback((model: FileModel, processedData: Transaction[]) => {
        if (!pendingTraining) return;
        const { type, entityId, content, fileName, rawFile } = pendingTraining;

        if (type === 'statement') {
            setBankStatementFile(prevFiles => {
                const existingIndex = prevFiles.findIndex(f => f.bankId === entityId);
                const newEntry = { bankId: entityId, content, fileName, rawFile, processedTransactions: processedData };
                if (existingIndex >= 0) {
                    const updated = [...prevFiles];
                    updated[existingIndex] = newEntry;
                    return updated;
                } else {
                    return [...prevFiles, newEntry];
                }
            });
            setSelectedBankIds(prev => prev.includes(entityId) ? prev : [...prev, entityId]);
            showToast("Extrato salvo!", "success");

            if (user && processedData.length > 0) {
                const consolidationData = processedData.map(t => ({
                    transaction_date: t.date,
                    amount: t.amount,
                    description: t.description,
                    type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                    pix_key: null,
                    source: 'file' as 'file',
                    user_id: user.id,
                    bank_id: entityId
                }));
                consolidationService.addTransactions(consolidationData).catch(() => {});
            }
        } else {
            const contributors: Contributor[] = processedData.map(t => ({
                name: t.description,
                cleanedName: t.cleanedDescription,
                normalizedName: normalizeString(t.description, cleaningKeywords),
                amount: t.amount,
                date: t.date,
                originalAmount: t.originalAmount,
                contributionType: t.contributionType
            }));
            setContributorFiles(prev => {
                const other = prev.filter(f => f.churchId !== entityId);
                return [...other, { churchId: entityId, content, fileName, contributors }];
            });
            showToast("Lista salva!", "success");
        }
        setPendingTraining(null);
    }, [pendingTraining, cleaningKeywords, setBankStatementFile, setContributorFiles, showToast, user, setSelectedBankIds]);

    const openLabManually = useCallback((targetFile?: { content: string, fileName: string, type: 'statement' | 'contributor', id: string, rawFile?: File }) => {
        if (targetFile) {
            setPendingTraining({ content: targetFile.content, fileName: targetFile.fileName, type: targetFile.type, entityId: targetFile.id, rawFile: targetFile.rawFile });
        } else if (activeBankFiles.length > 0) {
            const firstBank = activeBankFiles[0];
            setPendingTraining({ content: firstBank.content, fileName: firstBank.fileName, type: 'statement', entityId: firstBank.bankId, rawFile: firstBank.rawFile });
        } else {
            showToast("Carregue um arquivo primeiro.", "error");
        }
    }, [activeBankFiles, showToast]);

    // --- BLINDAGEM DA EXCLUSÃO ---
    const removeBankStatementFile = useCallback(async (bankId?: string) => {
        // 1. Atualização Otimista
        if (bankId) {
            setBankStatementFile(prev => prev.filter(f => f.bankId !== bankId));
            setSelectedBankIds(prev => prev.filter(id => id !== bankId));
        } else {
            setBankStatementFile([]);
            setSelectedBankIds([]);
        }

        // 2. Persistência Assíncrona Segura
        if (user) {
            consolidationService.deletePendingTransactions(user.id, bankId)
                .catch(e => {
                    // Log apenas, não trava a UI pois já foi removido visualmente
                    console.warn("[Consolidation] Delete sync warning:", e); 
                });
        }
    }, [setBankStatementFile, setSelectedBankIds, user]);

    const removeContributorFile = useCallback((churchId: string) => {
        setContributorFiles(prev => prev.filter(f => f.churchId !== churchId));
    }, [setContributorFiles]);

    const clearFiles = useCallback(() => {
        setBankStatementFile([]);
        setContributorFiles([]);
        setSelectedBankIds([]);
    }, [setBankStatementFile, setContributorFiles, setSelectedBankIds]);

    const resetReconciliation = useCallback(async () => {
        // 1. Limpeza Local
        setBankStatementFile([]);
        setContributorFiles([]);
        setMatchResults([]);
        setReportPreviewData(null);
        setHasActiveSession(false);
        setActiveReportId(null);
        setSelectedBankIds([]);

        // 2. Limpeza DB Segura
        if (user) {
            try {
                // Passa undefined explicitamente para indicar "delete all"
                await consolidationService.deletePendingTransactions(user.id, undefined);
                console.log("[Consolidation] Reset DB command sent.");
            } catch (e) {
                console.error("[Consolidation] Reset DB failed:", e);
            }
        }
        showToast("Ambiente limpo.", "success");
    }, [setBankStatementFile, setContributorFiles, setMatchResults, setReportPreviewData, setHasActiveSession, showToast, setActiveReportId, setSelectedBankIds, user]);

    // --- ENGINE ---
    const handleCompare = useCallback(async () => {
        if (selectedBankIds.length === 0 && !activeReportId) {
            showToast("Selecione pelo menos um banco.", "error");
            return;
        }

        setIsLoading(true);
        try {
            let activeTransactions: Transaction[] = [];

            if (activeBankFiles.length > 0) {
                const filesToProcess = activeBankFiles.filter(f => selectedBankIds.includes(f.bankId));
                activeTransactions = filesToProcess.flatMap(file => {
                    if (file.processedTransactions && file.processedTransactions.length > 0) {
                        return file.processedTransactions;
                    }
                    return processFileContent(file.content, file.fileName, fileModels, cleaningKeywords).transactions;
                });
            } else if (activeReportId && user) {
                try {
                    const dbTransactions = await consolidationService.getPendingTransactions(user.id);
                    activeTransactions = dbTransactions.map(dbTx => ({
                        id: dbTx.id,
                        date: dbTx.transaction_date,
                        amount: dbTx.amount,
                        description: dbTx.description,
                        cleanedDescription: dbTx.description,
                        contributionType: dbTx.type,
                        originalAmount: String(dbTx.amount)
                    }));
                } catch(e) {
                    activeTransactions = matchResults.filter(r => r.status === 'NÃO IDENTIFICADO').map(r => r.transaction);
                }
            } else if (activeReportId) {
                activeTransactions = matchResults.filter(r => r.status === 'NÃO IDENTIFICADO').map(r => r.transaction);
            }

            if (activeTransactions.length === 0) {
                showToast("Não há transações pendentes.", "error");
                return;
            }

            let filteredTransactions = activeTransactions;
            if (comparisonType === 'income') filteredTransactions = activeTransactions.filter(t => t.amount > 0);
            else if (comparisonType === 'expenses') filteredTransactions = activeTransactions.filter(t => t.amount < 0);

            const contributorData = contributorFiles.map(cf => {
                const church = churches.find(c => c.id === cf.churchId) || PLACEHOLDER_CHURCH;
                if (cf.contributors && cf.contributors.length > 0) return { church, contributors: cf.contributors };
                const listResult = processFileContent(cf.content, cf.fileName, fileModels, cleaningKeywords);
                const currentContributors = listResult.transactions.map(t => ({
                    name: t.description,
                    cleanedName: t.cleanedDescription,
                    normalizedName: normalizeString(t.description, cleaningKeywords),
                    amount: t.amount,
                    date: t.date,
                    originalAmount: t.originalAmount,
                    contributionType: t.contributionType
                }));
                return { church, contributors: currentContributors };
            });

            const newResults = matchTransactions(
                filteredTransactions, 
                contributorData, 
                { similarityThreshold: similarityLevel, dayTolerance }, 
                learnedAssociations, 
                churches, 
                cleaningKeywords
            );

            if (activeReportId) {
                setMatchResults(prevResults => {
                    const finalResults = [...prevResults];
                    newResults.forEach(newRes => {
                        const index = finalResults.findIndex(r => r.transaction.id === newRes.transaction.id);
                        if (index !== -1) {
                            const existing = finalResults[index];
                            if (existing.matchMethod === 'MANUAL' || existing.matchMethod === 'AI') return;
                            if (newRes.status === 'IDENTIFICADO' && existing.status !== 'IDENTIFICADO') finalResults[index] = newRes;
                            else if (newRes.suggestion && !existing.suggestion) finalResults[index] = newRes;
                        } else {
                            finalResults.push(newRes);
                        }
                    });
                    setReportPreviewData({
                        income: groupResultsByChurch(finalResults.filter(r => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                        expenses: { 'all_expenses_group': finalResults.filter(r => r.transaction.amount < 0) }
                    });
                    return finalResults;
                });
                showToast("Dados atualizados!", 'success');
            } else {
                setMatchResults(newResults);
                setReportPreviewData({
                    income: groupResultsByChurch(newResults.filter(r => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                    expenses: { 'all_expenses_group': newResults.filter(r => r.transaction.amount < 0) }
                });
                showToast("Conciliação finalizada!", 'success');
            }

            if (user) {
                const autoMatches = newResults.filter(r => r.status === 'IDENTIFICADO' && r.transaction.id && !r.transaction.id.startsWith('ghost-'));
                if (autoMatches.length > 0) {
                    const updatePromises = autoMatches.map(m => consolidationService.markAsIdentified(m.transaction.id).catch(() => {}));
                    Promise.all(updatePromises);
                }
            }

            setHasActiveSession(true);
            setActiveView('reports');

        } catch (e: any) {
            console.error(e);
            showToast("Erro ao processar.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [activeBankFiles, selectedBankIds, activeReportId, contributorFiles, churches, similarityLevel, dayTolerance, cleaningKeywords, learnedAssociations, setMatchResults, setReportPreviewData, setHasActiveSession, setActiveView, showToast, setIsLoading, comparisonType, fileModels, matchResults, user]);

    const updateReportData = useCallback((updatedRow: MatchResult, reportType: 'income' | 'expenses', idToRemove?: string) => {
        setMatchResults(prev => {
            let next = prev;
            if (idToRemove) next = next.filter(r => r.transaction.id !== idToRemove);
            return next.map(r => r.transaction.id === updatedRow.transaction.id ? updatedRow : r);
        });
        setReportPreviewData(prev => {
            if (!prev) return null;
            const newPreview = JSON.parse(JSON.stringify(prev));
            const targetGroup = reportType === 'expenses' ? newPreview.expenses : newPreview.income;
            if (reportType === 'income') {
                Object.keys(targetGroup).forEach(key => {
                    targetGroup[key] = targetGroup[key].filter((r: MatchResult) => {
                        const isTarget = r.transaction.id === updatedRow.transaction.id;
                        const isGhost = idToRemove && r.transaction.id === idToRemove;
                        return !isTarget && !isGhost;
                    });
                });
                const currentChurchId = updatedRow.church.id || 'unidentified';
                if (!newPreview.income[currentChurchId]) newPreview.income[currentChurchId] = [];
                newPreview.income[currentChurchId].push(updatedRow);
            } else {
                Object.keys(targetGroup).forEach(key => {
                    targetGroup[key] = targetGroup[key].map((r: MatchResult) => r.transaction.id === updatedRow.transaction.id ? updatedRow : r);
                });
            }
            return newPreview;
        });
    }, [setMatchResults, setReportPreviewData]);

    const discardCurrentReport = useCallback(() => {
        setMatchResults([]);
        setReportPreviewData(null);
        setHasActiveSession(false);
        setActiveReportId(null);
        setActiveView('upload');
    }, [setMatchResults, setReportPreviewData, setHasActiveSession, setActiveView, setActiveReportId]);

    const closeManualIdentify = useCallback(() => { setManualIdentificationTx(null); setBulkIdentificationTxs(null); }, []);
    const openManualMatchModal = useCallback((record: MatchResult) => { setManualMatchState({ record, suggestions: matchResults.map(r => r.transaction) }); }, [matchResults]);
    const closeManualMatchModal = useCallback(() => setManualMatchState(null), []);

    const confirmManualAssociation = useCallback((selectedTx: Transaction) => {
        if (!manualMatchState) return;
        const { record } = manualMatchState;
        const ghostIdToRemove = record.status === 'PENDENTE' ? record.transaction.id : undefined;
        const updatedResult: MatchResult = { ...record, transaction: selectedTx, status: 'IDENTIFICADO', matchMethod: 'MANUAL', similarity: 100 };
        updateReportData(updatedResult, 'income', ghostIdToRemove);
        closeManualMatchModal();
        showToast("Associado.", "success");
    }, [manualMatchState, updateReportData, closeManualMatchModal, showToast]);

    const openDivergenceModal = useCallback((match: MatchResult) => setDivergenceConfirmation(match), []);
    const closeDivergenceModal = useCallback(() => setDivergenceConfirmation(null), []);
    const confirmDivergence = useCallback((divergentMatch: MatchResult) => { updateReportData({ ...divergentMatch, status: 'IDENTIFICADO' }, 'income'); setDivergenceConfirmation(null); }, [updateReportData]);
    const rejectDivergence = useCallback((divergentMatch: MatchResult) => {
        if (divergentMatch.divergence?.expectedChurch) {
             const restored: MatchResult = { ...divergentMatch, church: divergentMatch.divergence.expectedChurch, status: 'IDENTIFICADO' };
             updateReportData(restored, 'income');
        } else {
             updateReportData({ ...divergentMatch, status: 'NÃO IDENTIFICADO', church: PLACEHOLDER_CHURCH, contributor: null }, 'income');
        }
        setDivergenceConfirmation(null);
    }, [updateReportData]);

    const handleAnalyze = useCallback(async (tx: Transaction, contributors: Contributor[]) => {
        setLoadingAiId(tx.id);
        setAiSuggestion(null);
        try {
            const result = await getAISuggestion(tx, contributors);
            setAiSuggestion({ id: tx.id, name: result });
        } catch (error) {
            console.error("AI Analysis failed", error);
            showToast("Falha na análise de IA", "error");
        } finally {
            setLoadingAiId(null);
        }
    }, [showToast, setLoadingAiId, setAiSuggestion]);

    const isCompareDisabled = selectedBankIds.length === 0 && !activeReportId;

    return useMemo(() => ({
        activeBankFiles, selectedBankIds, toggleBankSelection,
        bankStatementFile: activeBankFiles.length > 0 ? activeBankFiles[0] : null,
        contributorFiles, matchResults, setMatchResults, reportPreviewData, setReportPreviewData, hasActiveSession, setHasActiveSession,
        activeReportId, setActiveReportId, pendingTraining, setPendingTraining, comparisonType, setComparisonType,
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile, removeContributorFile, clearFiles, 
        handleCompare, updateReportData, discardCurrentReport, openLabManually, handleTrainingSuccess, resetReconciliation,
        manualIdentificationTx, setManualIdentificationTx, bulkIdentificationTxs, setBulkIdentificationTxs, closeManualIdentify,
        manualMatchState, setManualMatchState, openManualMatchModal, closeManualMatchModal, confirmManualAssociation,
        divergenceConfirmation, setDivergenceConfirmation, openDivergenceModal, closeDivergenceModal, confirmDivergence, rejectDivergence,
        loadingAiId, setLoadingAiId, aiSuggestion, setAiSuggestion, handleAnalyze,
        setBankStatementFile: (files: any) => setBankStatementFile(files),
        isCompareDisabled
    }), [activeBankFiles, selectedBankIds, toggleBankSelection, contributorFiles, matchResults, reportPreviewData, hasActiveSession, activeReportId, pendingTraining, comparisonType, handleStatementUpload, handleContributorsUpload, removeBankStatementFile, removeContributorFile, clearFiles, handleCompare, updateReportData, discardCurrentReport, openLabManually, handleTrainingSuccess, setMatchResults, setReportPreviewData, setHasActiveSession, setActiveReportId, resetReconciliation, manualIdentificationTx, bulkIdentificationTxs, closeManualIdentify, manualMatchState, openManualMatchModal, closeManualMatchModal, confirmManualAssociation, divergenceConfirmation, openDivergenceModal, closeDivergenceModal, confirmDivergence, rejectDivergence, loadingAiId, aiSuggestion, handleAnalyze, setBankStatementFile, isCompareDisabled]);
};

import { useState, useCallback, useMemo } from 'react';
import { supabase } from '../services/supabaseClient';
import { usePersistentState } from './usePersistentState';
import { SavedReport, SearchFilters, SavingReportState, MatchResult, SpreadsheetData } from '../types';

const DEFAULT_SEARCH_FILTERS: SearchFilters = {
    dateRange: { start: null, end: null },
    valueFilter: { operator: 'any', value1: null, value2: null },
    transactionType: 'all',
    reconciliationStatus: 'all',
    filterBy: 'none',
    churchIds: [],
    contributorName: '',
    reportId: null,
};

// LIMITE DE SEGURANÇA (Hard Limit)
// Ajustado para 60 relatórios (Equivalente a 5 anos de histórico mensal).
const MAX_REPORTS_PER_USER = 60;

export const useReportManager = (user: any | null, showToast: (msg: string, type: 'success' | 'error') => void) => {

    // --- User Scoping for Local Storage ---
    const userSuffix = user ? `-${user.id}` : '-guest';

    const [savedReports, setSavedReports] = useState<SavedReport[]>([]);
    const [searchFilters, setSearchFilters] = usePersistentState<SearchFilters>(`identificapix-search-filters${userSuffix}`, DEFAULT_SEARCH_FILTERS);

    const [isSearchFiltersOpen, setIsSearchFiltersOpen] = useState(false);
    const [savingReportState, setSavingReportState] = useState<SavingReportState | null>(null);

    // --- Search Filters Actions ---
    const openSearchFilters = useCallback(() => setIsSearchFiltersOpen(true), []);
    const closeSearchFilters = useCallback(() => setIsSearchFiltersOpen(false), []);
    const clearSearchFilters = useCallback(() => setSearchFilters(DEFAULT_SEARCH_FILTERS), [setSearchFilters]);

    // --- Saved Reports Actions ---
    const updateSavedReportName = useCallback(async (reportId: string, newName: string) => {
        if(!user) return;
        setSavedReports(prev => prev.map(r => r.id === reportId ? { ...r, name: newName } : r));
        const { error } = await supabase.from('saved_reports').update({ name: newName }).eq('id', reportId);
        if (error) showToast('Erro ao renomear relatório.', 'error');
        else showToast('Relatório renomeado.', 'success');
    }, [user, showToast]);

    const updateSavedReportTransaction = useCallback(async (transactionId: string, updatedRow: MatchResult) => {
        if (!user) return;

        // Find the report containing the transaction
        const reportIndex = savedReports.findIndex(r => r.data?.results.some(res => res.transaction.id === transactionId));

        if (reportIndex === -1) return;

        const report = savedReports[reportIndex];
        if (!report.data) return;

        // Create updated results array
        const updatedResults = report.data.results.map(res => 
            res.transaction.id === transactionId ? updatedRow : res
        );

        // Update Local State
        const updatedReport = {
            ...report,
            data: {
                ...report.data,
                results: updatedResults
            }
        };

        setSavedReports(prev => {
            const newReports = [...prev];
            newReports[reportIndex] = updatedReport;
            return newReports;
        });

        // Update Supabase
        const { error } = await supabase
            .from('saved_reports')
            .update({ data: updatedReport.data as any }) // Cast to any to satisfy Json type
            .eq('id', report.id);

        if (error) {
            showToast('Erro ao atualizar relatório salvo.', 'error');
        } else {
            showToast('Relatório salvo atualizado.', 'success');
        }
    }, [user, savedReports, setSavedReports, showToast]);

    // NOVO: Sobrescreve um relatório inteiro (usado para salvar alterações da sessão)
    // Agora aceita spreadsheetData opcional para atualizar planilhas
    const overwriteSavedReport = useCallback(async (reportId: string, results: MatchResult[], spreadsheetData?: SpreadsheetData) => {
        if (!user) return;

        const reportIndex = savedReports.findIndex(r => r.id === reportId);
        if (reportIndex === -1) return;

        const report = savedReports[reportIndex];

        // Determina a contagem de registros (planilha vs conciliação)
        const recordCount = spreadsheetData?.rows ? spreadsheetData.rows.length : results.length;

        const updatedReport: SavedReport = {
            ...report,
            recordCount: recordCount,
            data: {
                results: results,
                sourceFiles: [], // Mantém limpo ou preserva se necessário (simplificado)
                bankStatementFile: null,
                spreadsheet: spreadsheetData || report.data?.spreadsheet
            }
        };

        // Update Local State
        setSavedReports(prev => {
            const newReports = [...prev];
            newReports[reportIndex] = updatedReport;
            return newReports;
        });

        // OPTIMISTIC UI: Feedback Imediato
        showToast('Alterações salvas com sucesso!', 'success');

        // Update Supabase (Background)
        const { error } = await supabase
            .from('saved_reports')
            .update({ 
                data: updatedReport.data as any,
                record_count: recordCount 
            })
            .eq('id', reportId);

        if (error) {
            console.error("Erro ao persistir:", error);
            showToast('Aviso: Falha ao sincronizar com a nuvem. Verifique sua conexão.', 'error');
        }
    }, [user, savedReports, setSavedReports, showToast]);

    const saveFilteredReport = useCallback((results: MatchResult[]) => {
        setSavingReportState({
            type: 'search',
            results: results,
            groupName: 'Filtrado'
        });
    }, []);

    const openSaveReportModal = useCallback((state: SavingReportState) => setSavingReportState(state), []);
    const closeSaveReportModal = useCallback(() => setSavingReportState(null), []);

    const confirmSaveReport = useCallback(async (name: string) => {
        if (!savingReportState || !user) return;

        // CHECK DE LIMITE DE ARMAZENAMENTO
        if (savedReports.length >= MAX_REPORTS_PER_USER) {
            showToast(`Limite de ${MAX_REPORTS_PER_USER} relatórios atingido. Exclua alguns antigos para salvar novos.`, 'error');
            closeSaveReportModal();
            return;
        }

        const isSpreadsheet = savingReportState.type === 'spreadsheet';
        const recordCount = isSpreadsheet && savingReportState.spreadsheetData?.rows
            ? savingReportState.spreadsheetData.rows.length 
            : savingReportState.results.length;

        const newReport: SavedReport = {
            id: `rep-${Date.now()}`,
            name: name,
            createdAt: new Date().toISOString(),
            recordCount: recordCount,
            user_id: user.id,
            data: {
                results: savingReportState.results,
                sourceFiles: [],
                bankStatementFile: null,
                spreadsheet: isSpreadsheet ? savingReportState.spreadsheetData : undefined
            }
        };

        setSavedReports(prev => [newReport, ...prev]);
        closeSaveReportModal();

        const { error } = await supabase.from('saved_reports').insert({
            id: newReport.id,
            name: newReport.name,
            record_count: newReport.recordCount,
            user_id: newReport.user_id,
            data: newReport.data as any
        });

        if (error) {
            setSavedReports(prev => prev.filter(r => r.id !== newReport.id));
            showToast('Erro ao salvar relatório no banco de dados.', 'error');
        } else {
            showToast('Relatório salvo com sucesso!', 'success');
        }
    }, [savingReportState, user, showToast, closeSaveReportModal, savedReports.length]);

    // Função para deletar relatórios antigos em massa
    const deleteOldReports = useCallback(async (dateThreshold: Date) => {
        if (!user) return;

        const reportsToDelete = savedReports.filter(r => new Date(r.createdAt) < dateThreshold);
        if (reportsToDelete.length === 0) {
            showToast("Nenhum relatório encontrado anterior a esta data.", "error");
            return;
        }

        // Optimistic UI Update
        setSavedReports(prev => prev.filter(r => new Date(r.createdAt) >= dateThreshold));

        const { error } = await supabase
            .from('saved_reports')
            .delete()
            .lt('created_at', dateThreshold.toISOString())
            .eq('user_id', user.id);

        if (error) {
            // Revert state (complex, requires refetching usually, but simplified here)
            showToast("Erro ao excluir relatórios no servidor.", "error");
        } else {
            showToast(`${reportsToDelete.length} relatórios antigos foram excluídos.`, "success");
        }
    }, [user, savedReports, showToast]);

    const allHistoricalResults = useMemo(() => {
        return savedReports
            .filter(r => r.data && r.data.results)
            .flatMap(report => report.data!.results);
    }, [savedReports]);

    return useMemo(() => ({
        savedReports, setSavedReports,
        maxSavedReports: MAX_REPORTS_PER_USER, // EXPOSED CONSTANT
        searchFilters, setSearchFilters,
        isSearchFiltersOpen, openSearchFilters, closeSearchFilters, clearSearchFilters,
        savingReportState, openSaveReportModal, closeSaveReportModal, confirmSaveReport,
        updateSavedReportName, updateSavedReportTransaction, saveFilteredReport, overwriteSavedReport,
        deleteOldReports,
        allHistoricalResults
    }), [
        savedReports, searchFilters, isSearchFiltersOpen, savingReportState, allHistoricalResults,
        setSavedReports, setSearchFilters, openSearchFilters, closeSearchFilters, clearSearchFilters,
        openSaveReportModal, closeSaveReportModal, confirmSaveReport, updateSavedReportName, updateSavedReportTransaction, saveFilteredReport, overwriteSavedReport,
        deleteOldReports
    ]);
};

import { Logger } from "./monitoringService";
import { supabase } from "./supabaseClient";

// Escopos necessários
const GMAIL_SCOPES = 'https://www.googleapis.com/auth/gmail.readonly';

export const gmailService = {

    /**
     * Inicia o fluxo de autenticação para obter o token do Gmail.
     * Utiliza o Supabase Auth com escopos adicionais.
     */
    connect: async () => {
        const { error } = await (supabase.auth as any).signInWithOAuth({
            provider: 'google',
            options: {
                scopes: GMAIL_SCOPES,
                redirectTo: window.location.origin,
                queryParams: {
                    access_type: 'offline',
                    prompt: 'consent', // Força refresh token se necessário
                }
            }
        });
        if (error) throw error;
    },

    /**
     * Busca e-mails bancários recentes.
     * Requer que o usuário já tenha feito login com o escopo correto.
     * Aumentado para 400 para garantir recuperação pós-período desconectado ou eventos grandes.
     */
    fetchBankEmails: async (accessToken: string, maxResults = 400) => {
        try {
            // 1. Listar Mensagens (Filtro por keywords bancárias comuns)
            const query = 'subject:(pix OR transferência OR comprovante OR recebido OR enviado) -category:promotions -category:social';
            const listUrl = `https://gmail.googleapis.com/gmail/v1/users/me/messages?q=${encodeURIComponent(query)}&maxResults=${maxResults}`;

            const listResponse = await fetch(listUrl, {
                headers: { Authorization: `Bearer ${accessToken}` }
            });

            if (!listResponse.ok) {
                if (listResponse.status === 401) throw new Error("Token expirado ou inválido.");
                throw new Error("Falha ao listar e-mails.");
            }

            const listData = await listResponse.json();
            if (!listData.messages || listData.messages.length === 0) return [];

            // 2. Buscar Detalhes de cada mensagem (Batch requests seria ideal, mas fetch paralelo funciona para poucos itens)
            const messages = await Promise.all(listData.messages.map(async (msg: any) => {
                const detailUrl = `https://gmail.googleapis.com/gmail/v1/users/me/messages/${msg.id}?format=full`;
                const detailResponse = await fetch(detailUrl, {
                    headers: { Authorization: `Bearer ${accessToken}` }
                });
                return detailResponse.json();
            }));

            // 3. Simplificar Payload para a IA
            return messages.map((msg: any) => {
                const headers = msg.payload.headers;
                const subject = headers.find((h: any) => h.name === 'Subject')?.value || '';
                const date = headers.find((h: any) => h.name === 'Date')?.value || '';
                const snippet = msg.snippet;

                // Tenta extrair corpo texto (preferência text/plain)
                let body = '';
                if (msg.payload.parts) {
                    const part = msg.payload.parts.find((p: any) => p.mimeType === 'text/plain');
                    if (part && part.body.data) {
                        body = atob(part.body.data.replace(/-/g, '+').replace(/_/g, '/'));
                    }
                } else if (msg.payload.body.data) {
                    body = atob(msg.payload.body.data.replace(/-/g, '+').replace(/_/g, '/'));
                }

                return {
                    id: msg.id,
                    subject,
                    date,
                    snippet,
                    body
                };
            });

        } catch (error) {
            Logger.error("Erro no serviço Gmail", error);
            throw error;
        }
    }
};

import React, { useContext, useEffect, useState } from 'react';
import { AppContext } from '../../contexts/AppContext';
